#ifndef ESEC_HASH_BASICS_HEADER
#define ESEC_HASH_BASICS_HEADER

#include <stdint.h>
#include <stddef.h>

/** MD5 hash algorithm **/
#define ESEC_HASH_ALGO_MD5 0x01

/** SHA1 hash algorithm **/
#define ESEC_HASH_ALGO_SHA1 0x02

/** SHA224 hash algorithm **/
#define ESEC_HASH_ALGO_SHA224 0x03

/** SHA256 hash algorithm **/
#define ESEC_HASH_ALGO_SHA256 0x04

/** SHA384 hash algorithm **/
#define ESEC_HASH_ALGO_SHA384 0x05

/** SHA512 hash algorithm **/
#define ESEC_HASH_ALGO_SHA512 0x06

/** SM3 hash algorithm **/
#define ESEC_HASH_ALGO_SM3 0x0B

/** SHA3_224 hash algorithm **/
#define ESEC_HASH_ALGO_SHA3_224 0x07

/** SHA3_256 hash algorithm **/
#define ESEC_HASH_ALGO_SHA3_256 0x08

/** SHA3_384 hash algorithm **/
#define ESEC_HASH_ALGO_SHA3_384 0x09

/** SHA3_512 hash algorithm **/
#define ESEC_HASH_ALGO_SHA3_512 0x0A

/** Size in bytes of the digest generated by the SHA1 hash algorithm **/
#define ESEC_HASH_SIZE_SHA1 20

/** Size in bytes of the digest generated by the SHA224 hash algorithm **/
#define ESEC_HASH_SIZE_SHA224 28

/** Size in bytes of the digest generated by the SHA256 hash algorithm **/
#define ESEC_HASH_SIZE_SHA256 32

/** Size in bytes of the digest generated by the SHA384 hash algorithm **/
#define ESEC_HASH_SIZE_SHA384 48

/** Size in bytes of the digest generated by the SHA512 hash algorithm **/
#define ESEC_HASH_SIZE_SHA512 64

/** Size in bytes of the digest generated by the SM3 hash algorithm **/
#define ESEC_HASH_SIZE_SM3 32

/** Size in bytes of the digest generated by the SHA3_224 hash algorithm **/
#define ESEC_SHA3_HASH_SIZE_SHA224 28

/** Size in bytes of the digest generated by the SHA3_256 hash algorithm **/
#define ESEC_SHA3_HASH_SIZE_SHA256 32

/** Size in bytes of the digest generated by the SHA3_384 hash algorithm **/
#define ESEC_SHA3_HASH_SIZE_SHA384 48

/** Size in bytes of the digest generated by the SHA3_512 hash algorithm **/
#define ESEC_SHA3_HASH_SIZE_SHA512 64

/** SHA1 hash state size.
 *
 * Used in esec_hash_update() and esec_hash_finish() to keep the intermediate
 * hashing state between hash updates.
 **/
#define ESEC_HASH_STATE_SIZE_SHA1 20

/** SHA224 hash state size.
 *
 * Used in esec_hash_update() and esec_hash_finish() to keep the intermediate
 * hashing state between hash updates.
 **/
#define ESEC_HASH_STATE_SIZE_SHA224 32

/** SHA256 hash state size.
 *
 * Used in esec_hash_update() and esec_hash_finish() to keep the intermediate
 * hashing state between hash updates.
 **/
#define ESEC_HASH_STATE_SIZE_SHA256 32

/** SHA384 hash state size.
 *
 * Used in esec_hash_update() and esec_hash_finish() to keep the intermediate
 * hashing state between hash updates.
 **/
#define ESEC_HASH_STATE_SIZE_SHA384 64

/** SHA512 hash state size.
 *
 * Used in esec_hash_update() and esec_hash_finish() to keep the intermediate
 * hashing state between hash updates.
 **/
#define ESEC_HASH_STATE_SIZE_SHA512 64

/** SM3 hash state size.
 *
 * Used in esec_hash_update() and esec_hash_finish() to keep the intermediate
 * hashing state between hash updates.
 **/
#define ESEC_HASH_STATE_SIZE_SM3 32

/** SHA3 hash state size. */
#define ESEC_SHA3_HASH_STATE_SIZE 200

/** Message size granularity for SHA1 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA1 64

/** Message size granularity for SHA224 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA224 64

/** Message size granularity for SHA256 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA256 64

/** Message size granularity for SM3 hash with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SM3 64

/** Message size granularity for SHA384 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA384 128

/** Message size granularity for SHA512 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA512 128

/** Message size granularity for SHA3_224 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA3_224 144

/** Message size granularity for SHA3_256 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA3_256 136

/** Message size granularity for SHA3_384 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA3_384 104

/** Message size granularity for SHA3_512 with esec_hash_update(). **/
#define ESEC_HASH_BLOCK_SIZE_SHA3_512 72

extern const uint8_t esec_sha1_initial_state[ESEC_HASH_STATE_SIZE_SHA1];
extern const uint8_t esec_sha224_initial_state[ESEC_HASH_STATE_SIZE_SHA224];
extern const uint8_t esec_sha256_initial_state[ESEC_HASH_STATE_SIZE_SHA256];
extern const uint8_t esec_sha384_initial_state[ESEC_HASH_STATE_SIZE_SHA384];
extern const uint8_t esec_sha512_initial_state[ESEC_HASH_STATE_SIZE_SHA512];
extern const uint8_t esec_sm3_hash_initial_state[ESEC_HASH_STATE_SIZE_SM3];

#endif
